package com.retail.retailstoremanagement.controller;
import com.retail.retailstoremanagement.model.*;import jakarta.servlet.annotation.WebServlet;import jakarta.servlet.http.*;import java.io.IOException;
@WebServlet("/common/sidebar") public class SidebarServlet extends HttpServlet{
 protected void doGet(HttpServletRequest q,HttpServletResponse p)throws IOException{AppUser u=(AppUser)q.getSession().getAttribute("currentUser");String c=q.getContextPath();p.setContentType("text/html;charset=UTF-8");StringBuilder h=new StringBuilder("<div class=\"sidebar\"><div class=\"logo\"><i class=\"fa-solid fa-store me-2\"></i>Cửa Hàng ABC</div><ul class=\"sidebar-nav\">");link(h,c+"/dashboard","fa-chart-pie","Dashboard");if(u!=null&&u.getRole()==UserRole.ADMIN){link(h,c+"/products","fa-box-open","Sản phẩm");link(h,c+"/categories","fa-tags","Danh mục");link(h,c+"/inventory","fa-warehouse","Quản lý kho");}link(h,c+"/customers","fa-users","Khách hàng");link(h,c+"/sale.html","fa-cash-register","Bán hàng");link(h,c+"/invoices","fa-file-invoice","Hóa đơn");if(u!=null&&u.getRole()==UserRole.ADMIN)link(h,c+"/users","fa-user-shield","Tài khoản");h.append("<li class=\"mt-auto\"><a href=\"").append(c).append("/logout\" class=\"text-danger-hover\"><i class=\"fa-solid fa-right-from-bracket me-2\"></i>Đăng xuất</a></li></ul></div>");p.getWriter().print(h);}
 private void link(StringBuilder h,String url,String icon,String text){h.append("<li><a href=\"").append(url).append("\"><i class=\"fa-solid ").append(icon).append(" me-2\"></i>").append(text).append("</a></li>");}
}
